        scene1.sceneName = "Scene1";
        scene1.xFocus = 0.3f;
        scene1.startTime = 6;
        scene1.endTime = 12;
        scene1.startTime = 360;   // 06:00
        scene1.endTime = 720;     // 12:00

        scene2.startTime = 1080;  // 18:00
